FROM company_agents
WHERE region = 'North America' AND status = 'active';

SELECT agent_name
  FROM company_agents
  WHERE region = 'North America' AND status = 'active';

SELECT status_description
FROM shipment_statuses
WHERE is_final = 0;

SELECT COUNT(*) AS total_shipped_orders
  FROM shipping_histories
 WHERE status_id = 2 AND agent_id = 1;
